var score = 0;

var health = 5;

var gameState = "play";

var backgroundSprite = createSprite(200, 200);

backgroundSprite.setAnimation("sports_basketballhalf2_1");

var hoop = createSprite(200, 50);

hoop.setAnimation("mini hoo-p.jpg_1");

hoop.velocityX = 3;  

hoop.scale = 0.5; 

var ball = createSprite(200, 350);

ball.setAnimation("basketball_1");

ball.scale = 0.1; 

var spike = createSprite(200, -50);

spike.setAnimation("spike_bottom_1");

spike.scale = 0.5; 

function draw() { 

if (gameState === "play") { 

if (score >= 10) { 

backgroundSprite.setAnimation("court.jpg_1");

backgroundSprite.scale = 2.5;

    }

drawSprites(); 

handleInput(); 

moveHoop(); 

moveSpikes(); 

checkCollisions(); 

displayHUD(); 

checkWinLoss(); 

  } else if (gameState === "win") { 

backgroundSprite.scale = 2.5; 

backgroundSprite.setAnimation("you win'.jpg_1");

drawSprites(); 

  } else if (gameState === "lose") { 

backgroundSprite.scale = 2.5; 

backgroundSprite.setAnimation("you lose the game.png_1");

drawSprites(); 

  }

}

function handleInput() { 

if (keyDown("left")) { 

ball.x = ball.x - 5; 

  }

if (keyDown("right")) { 

ball.x = ball.x + 5; 

  }

if (keyDown("space")) { 

ball.velocityY = -10; 

  }

if (ball.y < 0) { 

ball.velocityY = 0; 

ball.y = 350; 

ball.x = 200; 

  }

}

function moveHoop() { 

if (hoop.x > 350) { 

hoop.velocityX = -4; 

  }

if (hoop.x < 50) { 

hoop.velocityX = 4; 

  }

}

function moveSpikes() { 

spike.y = spike.y + 5; 

spike.rotation += 5; 

if (spike.y > 400) { 

spike.y = -50; 

spike.x = randomNumber(50, 350); 

  }

}

function checkCollisions() { 

if (ball.isTouching(hoop) && ball.velocityY < 0) { 

score = score + 1; 

ball.velocityY = 0; 

ball.y = 350; 

ball.x = 200; 

  }

if (ball.isTouching(spike)) { 

health = health - 1; 

spike.y = -50;  

ball.y = 350; 

ball.x = 200; 

  }

}

function displayHUD() { 

fill("white"); 

textSize(20); 

text("Score: " + score, 10, 20); 

text("Health: " + health, 10, 40); 

}

function checkWinLoss() { 

if (score >= 20) { 

gameState = "win"; 

  }

if (health <= 0) { 

gameState = "lose"; 

  }

}
